//打开<工厂模型新建编辑_精灵图>
function showEditModelDialog(scope) {
  let clientInfomation = {
    clientGUID: "",
    clientName: "",
    repositoryName: "",
    repositoryGUID: "",
  };
  clientInfomation["clientGUID"] = scope.row.guid;
  clientInfomation["clientName"] = scope.row.modelname;
  clientInfomation["repositoryName"] = scope.row.repositoryname;
  clientInfomation["repositoryGUID"] = scope.row.repositoryguid;
  $Variable.选中人机界面客户端 = JSON.stringify(clientInfomation);

  const pageName = "编辑人机界面弹窗";
  const options = {
    type: 2, //弹出式页面样式配置
    styleOptions: {
      header: false,
      width: '500',
      height: '180',
      top: '300px',
    },
    sTType: 5,
    spaceTime: $Variable.配置后台时空全路径,
    variables: [{
        name: "选中人机界面客户端",
        value: $Variable.选中人机界面客户端
      },
      {
        name: "操作类型", // 操作类型
        value: "update"
      },
      {
        name: "配置后台对象名称",
        value: $Variable.配置后台名称
      },
      {
        name: "配置后台时空全路径",
        value: $Variable.配置后台时空全路径
      }
    ]
  };

  ShowChild(pageName, options, (res) => {
    debugger;
    if (res.eventName == "submit") {
      if (res.eventParam.length && res.eventParam[0].code === 0) {
        CloseChild(pageName);
        $Variable.queryClients = !$Variable.queryClients;
        $Variable.选中人机界面客户端 = "";
      }
    }
    if (res.eventName == "cancel") {
      CloseChild(pageName);
      $Variable.选中人机界面客户端 = "";
    }
  });
}

